diff --git a/FAQ.md b/FAQ.md
+## How do I convert a string to title case?
+
+Use `absl::AsciiStrToTitle()` from `absl/strings/ascii.h`:
+...
diff --git a/absl/strings/ascii.cc b/absl/strings/ascii.cc
+void AsciiStrToTitle(std::string* s) {
+  bool new_word = true;
+  for (char& c : *s) {
+    if (absl::ascii_isspace(...)) { new_word = true; }
+    else if (new_word) { c = absl::ascii_toupper(...); new_word = false; }
+    else { c = absl::ascii_tolower(...); }
+  }
+}
+
+std::string AsciiStrToTitle(absl::string_view s) {
+  std::string result(s);
+  absl::AsciiStrToTitle(&result);
+  return result;
+}
diff --git a/absl/strings/ascii.h b/absl/strings/ascii.h
+void AsciiStrToTitle(std::string* s);
+[[nodiscard]] std::string AsciiStrToTitle(absl::string_view s);
